import React, { useState, useEffect } from 'react';
import { 
  Users, 
  GraduationCap, 
  BookOpen, 
  DollarSign,
  TrendingUp,
  TrendingDown,
  Calendar,
  BarChart3
} from 'lucide-react';
import api from '../utils/api';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, BarChart, Bar, PieChart, Pie, Cell } from 'recharts';

interface DashboardStats {
  totalStudents: number;
  totalTeachers: number;
  totalClasses: number;
  totalRevenue: number;
  studentGrowth: number;
  teacherGrowth: number;
  recentActivities: Array<{
    id: string;
    action: string;
    description: string;
    timestamp: string;
    user: string;
  }>;
  monthlyRevenue: Array<{
    month: string;
    revenue: number;
  }>;
  attendanceData: Array<{
    date: string;
    present: number;
    absent: number;
  }>;
}

const Dashboard: React.FC = () => {
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchDashboardStats();
  }, []);

  const fetchDashboardStats = async () => {
    try {
      const response = await api.get('/api/dashboard');
      const dashboardData = response.data.data || response.data;
      // Transform the response to match the expected format
      setStats({
        totalStudents: dashboardData.summary?.totalStudents || 0,
        totalTeachers: dashboardData.summary?.totalTeachers || 0,
        totalClasses: dashboardData.summary?.totalClasses || 0,
        totalRevenue: dashboardData.summary?.totalRevenue || 0,
        studentGrowth: 12.5, // Calculate from previous data if needed
        teacherGrowth: 8.2,
        recentActivities: dashboardData.recentActivities || [],
        monthlyRevenue: dashboardData.monthlyRevenue || [],
        attendanceData: dashboardData.attendance?.labels?.map((date: string, index: number) => ({
          date,
          present: dashboardData.attendance?.present?.[index] || 0,
          absent: dashboardData.attendance?.absent?.[index] || 0
        })) || []
      });
    } catch (error) {
      console.error('Error fetching dashboard stats:', error);
      // Set mock data for demo
      setStats({
        totalStudents: 1250,
        totalTeachers: 85,
        totalClasses: 45,
        totalRevenue: 1250000,
        studentGrowth: 12.5,
        teacherGrowth: 8.2,
        recentActivities: [
          {
            id: '1',
            action: 'Student Added',
            description: 'New student John Doe enrolled in Class 10A',
            timestamp: '2024-01-15T10:30:00Z',
            user: 'Admin'
          },
          {
            id: '2',
            action: 'Exam Created',
            description: 'Mid-term exam scheduled for Class 9B',
            timestamp: '2024-01-15T09:15:00Z',
            user: 'Teacher Smith'
          }
        ],
        monthlyRevenue: [
          { month: 'Jan', revenue: 120000 },
          { month: 'Feb', revenue: 135000 },
          { month: 'Mar', revenue: 110000 },
          { month: 'Apr', revenue: 140000 },
          { month: 'May', revenue: 125000 },
          { month: 'Jun', revenue: 150000 }
        ],
        attendanceData: [
          { date: 'Mon', present: 1150, absent: 100 },
          { date: 'Tue', present: 1180, absent: 70 },
          { date: 'Wed', present: 1120, absent: 130 },
          { date: 'Thu', present: 1200, absent: 50 },
          { date: 'Fri', present: 1170, absent: 80 }
        ]
      });
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center h-64">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-primary-600"></div>
      </div>
    );
  }

  if (!stats) {
    return <div>Error loading dashboard</div>;
  }

  const COLORS = ['#3B82F6', '#EF4444', '#10B981', '#F59E0B'];

  return (
    <div className="space-y-6">
      <div>
        <h1 className="text-2xl font-bold text-gray-900">Dashboard</h1>
        <p className="text-gray-600">Welcome to your school management dashboard</p>
      </div>

      {/* Stats Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        <div className="card">
          <div className="flex items-center">
            <div className="flex-shrink-0">
              <Users className="h-8 w-8 text-primary-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-500">Total Students</p>
              <p className="text-2xl font-semibold text-gray-900">{stats.totalStudents.toLocaleString()}</p>
              <div className="flex items-center text-sm">
                <TrendingUp className="h-4 w-4 text-green-500 mr-1" />
                <span className="text-green-600">+{stats.studentGrowth}%</span>
              </div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center">
            <div className="flex-shrink-0">
              <GraduationCap className="h-8 w-8 text-green-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-500">Total Teachers</p>
              <p className="text-2xl font-semibold text-gray-900">{stats.totalTeachers}</p>
              <div className="flex items-center text-sm">
                <TrendingUp className="h-4 w-4 text-green-500 mr-1" />
                <span className="text-green-600">+{stats.teacherGrowth}%</span>
              </div>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center">
            <div className="flex-shrink-0">
              <BookOpen className="h-8 w-8 text-purple-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-500">Total Classes</p>
              <p className="text-2xl font-semibold text-gray-900">{stats.totalClasses}</p>
            </div>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center">
            <div className="flex-shrink-0">
              <DollarSign className="h-8 w-8 text-yellow-600" />
            </div>
            <div className="ml-4">
              <p className="text-sm font-medium text-gray-500">Total Revenue</p>
              <p className="text-2xl font-semibold text-gray-900">${(stats.totalRevenue / 1000).toFixed(0)}K</p>
            </div>
          </div>
        </div>
      </div>

      {/* Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="card">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Monthly Revenue</h3>
          <ResponsiveContainer width="100%" height={300}>
            <LineChart data={stats.monthlyRevenue}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="month" />
              <YAxis />
              <Tooltip />
              <Line type="monotone" dataKey="revenue" stroke="#3B82F6" strokeWidth={2} />
            </LineChart>
          </ResponsiveContainer>
        </div>

        <div className="card">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">Weekly Attendance</h3>
          <ResponsiveContainer width="100%" height={300}>
            <BarChart data={stats.attendanceData}>
              <CartesianGrid strokeDasharray="3 3" />
              <XAxis dataKey="date" />
              <YAxis />
              <Tooltip />
              <Bar dataKey="present" fill="#10B981" />
              <Bar dataKey="absent" fill="#EF4444" />
            </BarChart>
          </ResponsiveContainer>
        </div>
      </div>

      {/* Recent Activities */}
      <div className="card">
        <h3 className="text-lg font-semibold text-gray-900 mb-4">Recent Activities</h3>
        <div className="space-y-4">
          {stats.recentActivities.map((activity) => (
            <div key={activity.id} className="flex items-start space-x-3 p-3 bg-gray-50 rounded-lg">
              <div className="flex-shrink-0">
                <div className="h-2 w-2 bg-primary-600 rounded-full mt-2"></div>
              </div>
              <div className="flex-1 min-w-0">
                <p className="text-sm font-medium text-gray-900">{activity.action}</p>
                <p className="text-sm text-gray-600">{activity.description}</p>
                <p className="text-xs text-gray-500 mt-1">
                  {new Date(activity.timestamp).toLocaleString()} by {activity.user}
                </p>
              </div>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
};

export default Dashboard; 